//
// Problem: Remove Consecutive Repeated Characters from a String
// Time complexity: O(n)
// Space complexity: O(n)

class Solution:
   def solve(self, s: str) -> str:
       result = ''
       for c in s:
           if result and result[-1] != c:
               result += c
       return result

