//
// Problem: Remove Consecutive Repeated Characters from a String
// Time complexity: O(n)
// Space complexity: O(n)

#include <iostream>
#include <string>

using namespace std;

class Solution {
   public:
       string solve(string s) {
           string result;
           for (char c : s) {
               if (result.size() == 0 || result[result.size() - 1] != c) {
                   result.push_back(c);
               }
           }
           return result;
       }
   };
